import React, { useEffect, useRef, useState } from "react";
import { DataSet, Network } from "vis-network/standalone";
import { getGraphData } from "./create_graph";

// דוגמאות לייבוא, אפשר להוסיף עוד קבצים
import CS_evening_2026 from "./courses_jsons/courses_CS_evening_2026.json";
import CS_morning_2026 from "./courses_jsons/courses_CS_morning_2026.json";
import SE_morning_2026 from "./courses_jsons/courses_SE_morning_2026.json";
import CS_morning_2027 from "./courses_jsons/courses_CS_morning_2027.json";

function levelToLabel(level, semestersPerYear) {
  const years = ["1", "2", "3", "4"];
  const semesters = ["א", "ב", "קיץ"];

  const year = Math.floor(level / semestersPerYear);
  const semester = level % semestersPerYear;

  return `${years[year] || "?"}${semesters[semester] || "?"}`;
}

const availableTrees = [
  { label: CS_evening_2026.name, data: CS_evening_2026 },
  { label: CS_morning_2026.name, data: CS_morning_2026 },
  { label: SE_morning_2026.name, data: SE_morning_2026 },
  { label: CS_morning_2027.name, data: CS_morning_2027 },
];

export default function App() {
  const containerRef = useRef(null);
  const [selectedIndex, setSelectedIndex] = useState(0);

  const selectedTree = availableTrees[selectedIndex];
  const { nodes, edges, semestersPerYear } = getGraphData(
    selectedTree.data.courses,
  );

  // כל רמות השכבות לגרף התוויות הצמוד
  const allLevels = nodes.map((n) => n.level);
  const minLevel = Math.min(...allLevels);
  const maxLevel = Math.max(...allLevels);

  // שליפה מסודרת של כל הערכים הייחודיים של הרמות
  const levels = [...new Set(nodes.map((n) => n.level))].sort((a, b) => a - b);

  const totalHeight = Math.max(600, levels.length * 100);
  const labelHeight = totalHeight / (maxLevel - minLevel + 1);
  const graphWidth = "89%";

  useEffect(() => {
    const dataSet = {
      nodes: new DataSet(nodes),
      edges: new DataSet(edges),
    };

    const options = {
      layout: {
        hierarchical: {
          direction: "UD",
          sortMethod: "directed",
          levelSeparation: 115,
          nodeSpacing: 230, // ריווח אופקי רב למניעת חפיפות צמתים
        },
      },
      nodes: {
        shape: "box", // מלבן!
        margin: 10,
        font: { multi: true, size: 16, align: "center" },
        widthConstraint: { minimum: 120, maximum: 180 },
        heightConstraint: { minimum: 48 }, // מחזק צפיפות אנכית בריבועים
        borderWidth: 2,
      },
      edges: { arrows: "to" },
      physics: { enabled: false },
      interaction: {
        zoomView: false,
      },
    };

    const network = new Network(containerRef.current, dataSet, options);
    network.on("stabilizationIterationsDone", function () {
      network.fit({
        animation: false,
      });
    });
  }, [nodes, edges]);

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        height: "100vh",
        overflow: "hidden",
      }}
    >
      {/* אזור קבוע למעלה - לא גולל */}
      <div
        style={{
          backgroundColor: "white",
          borderBottom: "2px solid #e0e0e0",
          padding: "15px",
          flexShrink: 0,
        }}
      >
        <div style={{ textAlign: "center" }}>
          <select
            onChange={(e) => setSelectedIndex(Number(e.target.value))}
            value={selectedIndex}
            style={{ fontSize: "16px", padding: "8px" }}
          >
            {availableTrees.map((tree, idx) => (
              <option key={idx} value={idx}>
                {tree.label}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* אזור הגרף - גולל בנפרד */}
      <div
        style={{
          flex: 1,
          overflow: "auto",
          padding: "20px 0",
        }}
      >
        <div
          style={{ display: "flex", direction: "rtl", minHeight: totalHeight }}
        >
          {/* סרגל הסמסטרים בצד ימין */}
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "flex-end",
              height: totalHeight,
              width: "3em",
              fontSize: "18px",
              marginRight: "10px",
              marginTop: "0.5em",
            }}
          >
            {levels.map((level) => (
              <div
                key={level}
                style={{
                  height: labelHeight,
                  display: "flex",
                  alignItems: "center",
                }}
              >
                {levelToLabel(level, semestersPerYear)}
              </div>
            ))}
          </div>

          {/* מיכל הגרף */}
          <div
            ref={containerRef}
            style={{ height: totalHeight, width: graphWidth, margin: "0 auto" }}
          />
        </div>
      </div>
    </div>
  );
}
